def customer_total(order):
    total = 0
    for item, qty, price in order["items"]:
        total += qty * price
    return total

for order in orders:
    total = customer_total(order)
    print(f"{order['customer']} paid", total)

grand_total = sum(customer_total(o) for o in orders)
print("grand total", grand_total)
